import{_ as a,o as i,c as t,a0 as r}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"King Guide","description":"","frontmatter":{},"headers":[],"relativePath":"roles/king.md","filePath":"roles/king.md"}'),n={name:"roles/king.md"};function o(l,e,s,h,d,m){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="king-guide" tabindex="-1">King Guide <a class="header-anchor" href="#king-guide" aria-label="Permalink to &quot;King Guide&quot;">​</a></h1><p>This is the <strong>start here</strong> guide for <code>King</code> users. It is a kingdom-level reading path: what you run, what you cannot do, and where to go next for each job.</p><h2 id="what-a-king-is-responsible-for" tabindex="-1">What a King is responsible for <a class="header-anchor" href="#what-a-king-is-responsible-for" aria-label="Permalink to &quot;What a King is responsible for&quot;">​</a></h2><p>A King runs <strong>one kingdom</strong> and the alliances inside it. In practice that means:</p><ul><li>managing the kingdom and its alliances</li><li>creating users and assigning roles inside that kingdom</li><li>managing players, events, instances, imports, analytics, rewards, reports, and restore requests</li><li>offering premium kingdom grants to alliances</li></ul><p>For the broad role summary, start with <a href="./overview.html">Roles Explained</a>.</p><h2 id="the-most-important-rule-to-understand" tabindex="-1">The most important rule to understand <a class="header-anchor" href="#the-most-important-rule-to-understand" aria-label="Permalink to &quot;The most important rule to understand&quot;">​</a></h2><p>Kings have an <strong>ownership</strong> rule around deletion.</p><p>A King:</p><ul><li>can only delete users they created</li><li>can only delete alliances they created</li><li>can <strong>never</strong> delete Supreme Admin users</li><li>can <strong>never</strong> delete users who registered independently</li></ul><p>The exact blocked messages are already documented in <a href="./protection-rules.html">Safety Rules You&#39;ll Run Into</a>. Read that page early, because it explains the most confusing refusals Kings run into.</p><h2 id="your-main-reading-path" tabindex="-1">Your main reading path <a class="header-anchor" href="#your-main-reading-path" aria-label="Permalink to &quot;Your main reading path&quot;">​</a></h2><p>Start with these:</p><ol><li><a href="./../how-to/manage-kingdoms.html">Create &amp; Manage Kingdoms</a></li><li><a href="./../how-to/manage-alliances.html">Create &amp; Manage Alliances</a></li><li><a href="./../how-to/create-user.html">Create a User</a></li><li><a href="./../how-to/assign-roles.html">Assign or Remove Roles</a></li><li><a href="./../how-to/delete-user.html">Delete a User</a></li><li><a href="./../how-to/delete-restore-kingdom-alliance.html">Delete &amp; Restore Kingdoms/Alliances</a></li></ol><p>Then move into the daily operating guides:</p><ul><li><a href="./../how-to/players-directory.html">Players Directory</a></li><li><a href="./../events/templates-overview.html">Event Templates &amp; Instances Explained</a></li><li><a href="./../imports/overview.html">How Screenshot Imports Work</a></li><li><a href="./../analytics/overview.html">Analytics Overview</a></li><li><a href="./../how-to/reward-rules.html">Set Up Reward Rules</a></li><li><a href="./../how-to/rewards.html">Review Reward Eligibility</a></li></ul><h2 id="premium-and-grants" tabindex="-1">Premium and grants <a class="header-anchor" href="#premium-and-grants" aria-label="Permalink to &quot;Premium and grants&quot;">​</a></h2><p>Kings manage kingdom premium sharing from the kingdom side.</p><p>Read these together:</p><ul><li><a href="./../subscriptions/kingdom-grants.html">Grant Premium to Your Alliances</a></li><li><a href="./../subscriptions/allocations.html">Share Kingdom Quotas with Alliances</a></li><li><a href="./../subscriptions/effective-plan.html">Which Plan Applies to My Alliance?</a></li></ul><p>One important correction to remember: the number of alliances you can grant is <strong>not</strong> a fixed platform-wide number. It comes from the kingdom plan&#39;s current grant-slot limit.</p><h2 id="things-a-king-cannot-do" tabindex="-1">Things a King cannot do <a class="header-anchor" href="#things-a-king-cannot-do" aria-label="Permalink to &quot;Things a King cannot do&quot;">​</a></h2><p>A King cannot:</p><ul><li>manage the global subscriptions dashboard</li><li>create or edit plans</li><li>suspend kingdoms or alliances</li><li>handle admin subscription requests</li><li>configure support links</li><li>manage platform roles and permission catalogs</li></ul><p>Those are Supreme-Admin-only areas. See <a href="./supreme-admin.html">Supreme Admin Guide</a> if you need the platform-level map.</p><h2 id="good-pages-to-keep-bookmarked" tabindex="-1">Good pages to keep bookmarked <a class="header-anchor" href="#good-pages-to-keep-bookmarked" aria-label="Permalink to &quot;Good pages to keep bookmarked&quot;">​</a></h2><ul><li><a href="./../how-to/my-alliance.html">My Alliance</a> for seeing what alliance leaders see</li><li><a href="./../reference/audit-logs.html">Read the Audit Logs</a></li><li><a href="./../how-to/recycle-bin.html">Use the Recycle Bin</a></li><li><a href="./../how-to/restore-requests.html">Request &amp; Approve Restores</a></li></ul>',27)])])}const u=a(n,[["render",o]]);export{p as __pageData,u as default};
